            </div>
            <div className="space-y-6">
              <h2 className="text-6xl lg:text-8xl font-black uppercase tracking-tighter text-white leading-none">DITES <br/><span className="text-[#E10600]">« OK FIKO »</span></h2>
              <p className="text-slate-500 font-medium uppercase tracking-[0.4em] text-sm">POUR ACTIVER LE SYSTÈME ET DÉMARRER</p>
            </div>
            <div className="space-y-4">
              <button 
                onClick={startVocalSession} 
                className="group relative bg-[#E10600] text-white px-16 py-10 font-black text-xs uppercase tracking-[0.6em] shadow-2xl flex items-center gap-8 mx-auto hover:scale-105 transition-all overflow-hidden"
