        )}

        {/* STEP 2: CONNECTING */}
        {step === 'connecting' && (
          <motion.div 
            key="connecting"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="flex flex-col items-center gap-12"
          >
            <Loader2 size={100} className="text-[#E10600] animate-spin" />
            <div className="text-center space-y-4">
              <h3 className="text-3xl font-black uppercase tracking-widest animate-pulse">LIAISON NEURALE...</h3>
              <p className="text-slate-600 font-black text-[10px] uppercase tracking-[0.8em]">Analyse du canal de confiance v1.3</p>
            </div>
          </motion.div>
        )}

        {/* STEP 3: ACTIVE */}
        {step === 'active' && (
          <motion.div 
            key="active"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }}
            className="flex flex-col items-center justify-center h-full w-full max-w-6xl"
          >
             <div className="flex items-center justify-center gap-3 h-64 w-full mb-20 relative">
               {bars.map((h, i) => (
                 <motion.div 
                    key={i} 
                    className="w-2 md:w-3 bg-[#E10600] rounded-full transition-all duration-75" 
                    style={{ 
                      height: `${h}%`, 
                      opacity: (h / 100) * 0.6 + 0.4,
                      boxShadow: h > 60 ? `0 0 20px #E10600` : 'none'
