                <p className="text-2xl lg:text-4xl text-white font-light italic leading-relaxed">
                  {transcription ? `« ${transcription} »` : "FIKO™ analyse votre besoin stratégique..."}
                </p>
                {transcription && (
                  <motion.div 
                    initial={{ scaleX: 0 }} animate={{ scaleX: 1 }}
                    className="h-0.5 bg-[#E10600] mt-10 origin-left"
                  ></motion.div>
                )}
             </div>
          </motion.div>
        )}

      </AnimatePresence>

      <footer className="absolute bottom-10 w-full px-10 flex justify-between items-center opacity-30 select-none">
         <div className="flex items-center gap-4">
            <ShieldAlert size={14} className="text-[#E10600]" />
            <p className="text-[8px] font-black uppercase tracking-widest text-slate-500">Vertex AI Real-time // Master Logic: FIKO_v1.3</p>
