};

export default VocalSalesOverlay;

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Settings, Volume2, Loader2, PhoneOff, AlertTriangle, ShieldCheck, Activity, Hexagon, Sparkles, RefreshCw, ShieldAlert } from 'lucide-react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { FIKO_MASTER_CLOSER_PROMPT } from '../constants';

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const VoicePage: React.FC = () => {
  const [isConnecting, setIsConnecting] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(30).fill(5));
  const [statusText, setStatusText] = useState("SYSTÈME PRÊT AU DÉPLOIEMENT");
  const [transcription, setTranscription] = useState("");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const retryCountRef = useRef(0);
  const isClosingRef = useRef(false);

  useEffect(() => {
    return () => stopSession();
  }, []);

  const createBlob = (data: Float32Array) => {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startSession = async () => {
    if (isClosingRef.current) return;
    setIsConnecting(true);
    setError(null);
    setStatusText("SYNCHRONISATION NEURALE...");

    try {
      const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
      if (!AudioContextClass) throw new Error("AudioContext not supported");

      const inputCtx = new AudioContextClass({ sampleRate: 16000 });
      const outputCtx = new AudioContextClass({ sampleRate: 24000 });

      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (isClosingRef.current) return;
            setIsConnecting(false);
            setIsActive(true);
            setStatusText("LIAISON NEURALE ÉTABLIE");
            retryCountRef.current = 0;

            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 500 + 10)) + 5));

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: createBlob(inputData) });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (isClosingRef.current) return;

            if (message.serverContent?.inputTranscription) {
                setTranscription(message.serverContent.inputTranscription.text);
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error('Krypton Link Error:', e);
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: `${FIKO_MASTER_CLOSER_PROMPT}\n\nDIRECTIVE CRITIQUE : Active le SHADOW MODE en temps réel. Analyse chaque signal, matche avec le wiki et vérifie la cohérence avant de générer l'audio. Pas d'improvisation.`
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error(err);
      setError("Accès audio refusé. Vérifiez vos permissions.");
      setIsConnecting(false);
    }
  };

  const stopSession = () => {
    isClosingRef.current = true;
    setIsActive(false);
    setIsConnecting(false);
    setTranscription("");

    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();

    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;

    if (sessionRef.current) sessionRef.current.close();
    sessionRef.current = null;

    setBars(new Array(30).fill(5));
    nextStartTimeRef.current = 0;
    setStatusText("SYSTÈME PRÊT AU DÉPLOIEMENT");
    isClosingRef.current = false;
  };

  return (
    <div className="relative h-[calc(100vh-80px)] overflow-hidden bg-[#0B0B0F] flex flex-col items-center justify-center">
      <div className="absolute inset-0 bg-gradient-to-b from-[#E10600]/5 to-transparent pointer-events-none"></div>
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

      <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-[#E10600]/20 to-transparent"></div>

