        <X size={32} className="group-hover:rotate-90 transition-transform" />
      </button>

      <AnimatePresence mode="wait">

        {/* HUD ANALYTIQUE (Seulement si actif) */}
        {step === 'active' && (
          <motion.div 
            initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}
            className="absolute top-12 left-10 z-50 flex flex-col gap-6 w-80"
          >
             <div className="p-8 border border-white/10 bg-black/50 backdrop-blur-2xl rounded-sm shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1 h-full bg-[#E10600]"></div>
                <div className="flex justify-between items-center mb-6">
                   <div className="flex items-center gap-3">
                     <Target size={18} className="text-[#E10600]" />
                     <span className="text-[10px] font-black uppercase tracking-[0.3em] text-white">PRIORITY_ML</span>
                   </div>
                   <span className={`text-2xl font-black ${priorityScore >= 75 ? 'text-[#E10600]' : 'text-white'}`}>{priorityScore}</span>
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div className="bg-white/5 p-3 rounded-sm border border-white/5">
