                      <p className="text-[8px] font-black text-slate-500 uppercase mb-1">LTV Predict</p>
                      <p className={`text-xs font-bold uppercase ${ltvClass === 'PLATINUM' ? 'text-[#E10600]' : 'text-white'}`}>{ltvClass}</p>
                   </div>
                </div>
                <div className="mt-6 pt-6 border-t border-white/5 flex flex-col gap-3">
