} from 'lucide-react';

interface ClientDashboardPageProps {
  onNavigate: (p: Page) => void;
  gate: string;
}

const ClientDashboardPage: React.FC<ClientDashboardPageProps> = ({ onNavigate, gate }) => {
  const theme = GATE_THEMES[gate] || GATE_THEMES.MARS;
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'project' | 'documents' | 'billing' | 'chat' | 'notifications' | 'timeline'>('overview');

  const [project] = useState<Project>(MOCK_CLIENT_PROJECT);
  const [notifications, setNotifications] = useState<KryptonNotification[]>(MOCK_NOTIFICATIONS);
  const [documents] = useState<KryptonDocument[]>(MOCK_CLIENT_DOCS);
  const [messages, setMessages] = useState<Message[]>([]);
  const [timeline, setTimeline] = useState<FollowUpRecord[]>([]);
  const [fikoInsight, setFikoInsight] = useState<string>("Analyse neurale v1.2 active...");
  const [showInactivityRelance, setShowInactivityRelance] = useState(false);

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inactivityTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      generateInitialFikoInsight();

      const savedMsgs = localStorage.getItem(`krypton_fiko_history_${gate}`);
      if (savedMsgs) {
        setMessages(JSON.parse(savedMsgs));
      } else {
        setMessages([{
          role: 'model',
          text: `Bonjour. Système v1.3 opérationnel. Votre Porte ${gate} est sous monitoring constant. Souhaitez-vous un audit de performance ?`,
          timestamp: new Date().toLocaleTimeString()
        }]);
      }

      setTimeline([
        { id: 'T-1', targetId: '1', targetName: 'Moi', channel: 'email', scenario: 'CONFIRMATION', tone: 'strategique', message: 'Email de bienvenue envoyé.', sentAt: new Date(Date.now() - 86400000).toISOString(), status: 'opened', type: 'auto' },
        { id: 'T-2', targetId: '1', targetName: 'Moi', channel: 'chat', scenario: 'QUALIFICATION', tone: 'soft', message: 'Échange initial sur les objectifs.', sentAt: new Date(Date.now() - 43200000).toISOString(), status: 'responded', type: 'manual' }
      ]);
    }, 1500);

    // Initialiser le timer d'inactivité (simulé court pour les tests E2E)
    resetInactivityTimer();

    return () => {
      clearTimeout(timer);
      if (inactivityTimerRef.current) clearTimeout(inactivityTimerRef.current);
    };
