class VisitorMemorySystem {
  private COOKIE_NAME = 'fiko_id';
  private STORAGE_KEY = 'krypton_visitor_identity';

  /**
   * Génère une empreinte probabiliste du navigateur
   */
  private generateFingerprint(): string {
    const canvas = document.createElement('canvas');
    const gl = canvas.getContext('webgl') as WebGLRenderingContext;
    const debugInfo = gl?.getExtension('WEBGL_debug_renderer_info');
    const renderer = debugInfo ? gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) : '';

    const signature = [
      navigator.userAgent,
      navigator.language,
      screen.colorDepth,
      screen.width + 'x' + screen.height,
      new Date().getTimezoneOffset(),
      renderer,
      !!window.indexedDB,
      !!window.sessionStorage
    ].join('###');

    // Simple hash (simulation)
    let hash = 0;
    for (let i = 0; i < signature.length; i++) {
      const char = signature.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return 'fiko_fp_' + Math.abs(hash).toString(36);
  }

  private setCookie(name: string, value: string, days: number) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    const expires = "; expires=" + date.toUTCString();
    document.cookie = name + "=" + (value || "") + expires + "; path=/; SameSite=Strict; Secure";
  }

  private getCookie(name: string): string | null {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for (let i = 0; i < ca.length; i++) {
      let c = ca[i];
      while (c.charAt(0) === ' ') c = c.substring(1, c.length);
      if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
  }

  /**
   * Tente de récupérer une identité connue
   */
  public getIdentity(): ProspectInfo | null {
    // 1. Check Local Storage
    const stored = localStorage.getItem(this.STORAGE_KEY);
    if (stored) return JSON.parse(stored);

    // 2. Check Cookie (pour les retours après wipe storage)
    const cookieId = this.getCookie(this.COOKIE_NAME);
    if (cookieId) {
      // Si on a le cookie mais pas le storage, on peut potentiellement 
      // faire un appel API pour récupérer les infos si on avait un backend.
      // Ici, on retourne null car on a besoin du prénom/email.
    }

    return null;
  }

  /**
   * Mémorise un nouveau prospect
   */
  public saveIdentity(info: ProspectInfo) {
    const visitorId = this.generateFingerprint();
    const fullIdentity = {
      ...info,
      visitorId,
      lastSeen: new Date().toISOString()
    };

    localStorage.setItem(this.STORAGE_KEY, JSON.stringify(fullIdentity));
    this.setCookie(this.COOKIE_NAME, visitorId, 365);

    return fullIdentity;
  }

  /**
   * Supprime l'identité (Logout FIKO)
   */
  public forget() {
    localStorage.removeItem(this.STORAGE_KEY);
    this.setCookie(this.COOKIE_NAME, '', -1);
  }
}

