  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [soundEnabled, setSoundEnabled] = useState(true);

  // Overlays State
  const [fikoChat, setFikoChat] = useState<{ open: boolean; agent: Agent | null }>({ open: false, agent: null });
  const [fikoVocal, setFikoVocal] = useState<{ open: boolean; porte?: string; initialStep?: FikoFlowStep }>({ open: false });
  const [showCaptureModal, setShowCaptureModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<{ type: 'vocal' | 'chat' | 'page'; data?: any } | null>(null);

  // System Transitions State
  const [activeGateTransition, setActiveGateTransition] = useState<string | null>(null);
  const [showGateAuth, setShowGateAuth] = useState<string | null>(null);
  const [orderModal, setOrderModal] = useState<{ open: boolean; porte: string }>({ open: false, porte: '' });
  const [selectedGate, setSelectedGate] = useState<string>('MARS');
  const [magicLinkLoading, setMagicLinkLoading] = useState(false);

  useEffect(() => {
    soundEngine.setEnabled(soundEnabled);

    // 1. Détection Magic Link (Cross-Device)
    const urlParams = new URLSearchParams(window.location.search);
    const token = urlParams.get('fiko_token');

    if (token) {
      setMagicLinkLoading(true);
      const context = visitorMemory.decodeMagicToken(token);
      if (context) {
        setProspect(context.prospect);
        visitorMemory.saveIdentity(context.prospect); // Persister sur ce nouvel appareil
        if (context.gate) setSelectedGate(context.gate);

        // Ouvrir FIKO automatiquement après un court délai pour l'effet "Reconnaissance"
        setTimeout(() => {
          setMagicLinkLoading(false);
          setFikoChat({ open: true, agent: MASTER_AGENTS[0] });
          // Nettoyer l'URL
          window.history.replaceState({}, document.title, window.location.pathname);
        }, 2000);
      } else {
        setMagicLinkLoading(false);
      }
    } else {
      // 2. Reconnaissance locale standard
      const memoryIdentity = visitorMemory.getIdentity();
      if (memoryIdentity) {
        setProspect(memoryIdentity);
      }
    }
  }, [soundEnabled]);

  const navigateTo = (page: Page) => {
    if (page === Page.FIKO && !prospect && !user) {
      setPendingAction({ type: 'page' });
      setShowCaptureModal(true);
      return;
    }
    setCurrentPage(page);
    window.scrollTo(0, 0);
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    if (profile.role === UserRole.SUPER_ADMIN || profile.role === UserRole.ADMIN) {
      navigateTo(Page.ADMIN_DASHBOARD);
    } else {
      navigateTo(Page.CLIENT_DASHBOARD);
    }
  };

  const handleLogout = () => {
    setUser(null);
    visitorMemory.forget();
    navigateTo(Page.HOME);
  };

  const openFikoVocal = (porte?: string, initialStep?: FikoFlowStep) => {
    if (!prospect && !user) {
      setPendingAction({ type: 'vocal', data: { porte, initialStep } });
      setShowCaptureModal(true);
      return;
    }
    setFikoVocal({ open: true, porte, initialStep });
  };

  const openFikoChat = (agent: Agent) => {
    if (!prospect && !user) {
      setPendingAction({ type: 'chat', data: { agent } });
      setShowCaptureModal(true);
      return;
    }
    setFikoChat({ open: true, agent });
  };

  const handleCaptureSubmit = (info: ProspectInfo) => {
    const savedIdentity = visitorMemory.saveIdentity(info);
    setProspect(savedIdentity);

    const newLead: Lead = {
      id: `L-${Date.now()}`,
      entity: info.firstName,
      email: info.email,
      category: 'Prospect Direct',
      priorityScore: 50,
      riskScore: 0,
      riskLevel: 'FAIBLE',
      mlRiskProb: 0,
      riskWindow: '30_DAYS',
      buyingMoment: BuyingWindow.LATER,
      mlClosingProb: 0.1,
      status: 'warm',
      gate: 'NONE',
      lastInteraction: new Date().toISOString(),
      autopilotState: { status: 'OBSERVATION', sessionHistory: [] }
    };

    const existingLeads = JSON.parse(localStorage.getItem('krypton_crm_leads') || '[]');
    localStorage.setItem('krypton_crm_leads', JSON.stringify([...existingLeads, newLead]));

    setShowCaptureModal(false);

    if (pendingAction) {
      if (pendingAction.type === 'vocal') {
        setFikoVocal({ open: true, ...pendingAction.data });
      } else if (pendingAction.type === 'chat') {
        setFikoChat({ open: true, agent: pendingAction.data.agent });
      } else if (pendingAction.type === 'page') {
        setCurrentPage(Page.FIKO);
      }
      setPendingAction(null);
    }
  };

  const handleGateChoice = (gate: string) => {
    setActiveGateTransition(gate);
    setSelectedGate(gate);
  };

  const handleTransitionComplete = useCallback(() => {
    const gate = activeGateTransition;
    setActiveGateTransition(null);
    setShowGateAuth(gate);
  }, [activeGateTransition]);

  const handleAuthSuccess = () => {
    const gate = showGateAuth || 'MARS';
    setShowGateAuth(null);
    setOrderModal({ open: true, porte: gate });
  };

  const handleOrderComplete = (porte: string) => {
    setOrderModal({ open: false, porte: '' });
    setSelectedGate(porte);
    navigateTo(Page.CLIENT_DASHBOARD);
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME: return <HomePage onNavigate={navigateTo} onOpenFiko={() => openFikoVocal()} />;
      case Page.FIKO: return <FikoPage onNavigate={navigateTo} onOpenGate={handleGateChoice} prospect={prospect || undefined} />;
      case Page.AGENTS: return <AgentsPage onOpenFiko={() => openFikoVocal()} onOpenChat={openFikoChat} />;
      case Page.VOICE: return <VoicePage />;
      case Page.CRM: return <CRMPage />;
      case Page.SCRAPER: return <ScraperPage />;
      case Page.PRICING: return <PricingPage onNavigate={navigateTo} onOpenFiko={handleGateChoice} />;
      case Page.TRUST: return <TrustPage onNavigate={navigateTo} />;
      case Page.WHITEPAPER: return <WhitepaperPage onNavigate={navigateTo} />;
      case Page.CLIENT_DASHBOARD: return <ClientDashboardPage onNavigate={navigateTo} gate={selectedGate} />;
      case Page.ADMIN_DASHBOARD: return <AdminDashboardPage onNavigate={navigateTo} user={user} onLogout={handleLogout} />;
      case Page.AUTH: return <AuthPage onLoginSuccess={handleLoginSuccess} onNavigate={navigateTo} />;
      default: return <HomePage onNavigate={navigateTo} onOpenFiko={() => openFikoVocal()} />;
    }
  };

  const isFullImmersion = [Page.CLIENT_DASHBOARD, Page.ADMIN_DASHBOARD, Page.AUTH, Page.FIKO].includes(currentPage);

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex flex-col selection:bg-[#E10600] selection:text-white font-sans overflow-x-hidden">
      {!isFullImmersion && (
        <Navbar 
          activePage={currentPage} 
          onNavigate={navigateTo}
          user={user}
          onLogout={handleLogout}
        />
      )}

      <main className="flex-grow">
        {renderPage()}
      </main>

      {!isFullImmersion && <Footer onNavigate={navigateTo} />}

      {!isFullImmersion && (
        <div className="fixed bottom-6 right-6 z-50 flex flex-col items-center gap-4">
          <button 
            onClick={() => setSoundEnabled(!soundEnabled)}
            className="size-12 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-slate-500 hover:text-white transition-all backdrop-blur-xl"
          >
            {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
          </button>
          <button 
            onClick={() => openFikoVocal()}
            className="relative group p-4 transition-all hover:scale-110 active:scale-95"
          >
            <div className="absolute inset-0 bg-[#E10600]/20 blur-3xl rounded-full animate-fiko-fluo"></div>
            <div className="absolute inset-0 border border-[#E10600]/40 rounded-full animate-fiko-fluo scale-110 opacity-50"></div>
            <div className="relative bg-black rounded-full p-6 border border-[#E10600]/30 shadow-[0_0_30px_rgba(225,6,0,0.2)]">
              <Hexagon size={80} className="text-[#E10600] drop-shadow-[0_0_25px_#E10600] animate-hex-orbit" strokeWidth={2.5} />
              <span className="absolute inset-0 flex items-center justify-center text-[11px] font-black uppercase tracking-[0.3em] text-white neon-fiko">FIKO™</span>
            </div>
          </button>
        </div>
      )}

      {magicLinkLoading && (
        <div className="fixed inset-0 z-[300] bg-black/95 backdrop-blur-3xl flex flex-col items-center justify-center gap-10">
           <div className="relative">
              <Hexagon size={120} className="text-[#E10600] animate-[spin_8s_linear_infinite]" strokeWidth={1} />
              <div className="absolute inset-0 flex items-center justify-center">
                 <Sparkles size={40} className="text-[#E10600] animate-pulse" />
              </div>
           </div>
           <div className="text-center space-y-4">
              <h2 className="text-4xl font-black uppercase tracking-tighter italic">RECONNAISSANCE <br/><span className="text-[#E10600]">CROSS-DEVICE.</span></h2>
              <p className="text-slate-500 uppercase tracking-[0.6em] text-[9px] font-black animate-pulse">Restauration du contexte neural en cours...</p>
           </div>
        </div>
      )}

      {showCaptureModal && (
        <FikoCaptureModal 
          onClose={() => setShowCaptureModal(false)}
          onSubmit={handleCaptureSubmit}
        />
      )}

      {fikoChat.open && (
        <AIChatOverlay 
          agent={fikoChat.agent} 
          prospectName={prospect?.firstName || user?.firstName}
          onClose={() => setFikoChat({ open: false, agent: null })} 
        />
      )}

      {fikoVocal.open && (
        <VocalSalesOverlay 
          agent={MASTER_AGENTS[0]} 
          prospectName={prospect?.firstName || user?.firstName}
          onClose={() => setFikoVocal({ open: false })} 
          onOpenCheckout={(porte) => { setFikoVocal({ open: false }); handleGateChoice(porte); }}
          initialPorte={fikoVocal.porte}
        />
      )}

      {activeGateTransition && <GateTransition gate={activeGateTransition} onComplete={handleTransitionComplete} />}
      {showGateAuth && <GateAuthModal gate={showGateAuth} onSuccess={handleAuthSuccess} onClose={() => setShowGateAuth(null)} />}
      {orderModal.open && <OrderModal porte={orderModal.porte} onClose={() => setOrderModal({ open: false, porte: '' })} onComplete={handleOrderComplete} />}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Agent, Message, FollowUpRecord, ProspectInfo } from '../types';
import { FIKO_MASTER_CLOSER_PROMPT, FIKO_EMAIL_TEMPLATES } from '../constants';
import { visitorMemory } from '../utils/VisitorMemory';
// Added missing Network and Activity icons
import { X as LucideX, Send as LucideSend, Bot as LucideBot, User as LucideUser, ShieldCheck as LucideShieldCheck, Sparkles as LucideSparkles, ShieldAlert as LucideShieldAlert, Clock as LucideClock, Network as LucideNetwork, Activity as LucideActivity, Link as LucideLink, Smartphone as LucideSmartphone, Check as LucideCheck, Loader2 as LucideLoader2 } from 'lucide-react';

interface AIChatOverlayProps {
  agent: Agent | null;
  prospectName?: string;
  onClose: () => void;
}

const AIChatOverlay: React.FC<AIChatOverlayProps> = ({ agent, prospectName, onClose }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [magicLinkSent, setMagicLinkSent] = useState(false);
  const [isSendingLink, setIsSendingLink] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const storageKey = `krypton_fiko_chat_history_${agent?.id || 'default'}`;

  useEffect(() => {
    if (agent) {
      const savedHistory = localStorage.getItem(storageKey);
      if (savedHistory) {
        setMessages(JSON.parse(savedHistory));
      } else {
        // GREETING PROTOCOLE OPÉRATIONNEL FIKO
        const initialMsg: Message = { 
          role: 'model', 
          text: `Bonjour ${prospectName || 'à vous'},\nje suis FIKO. Merci d’avoir pris le temps. Parlons de ce que vous cherchez à mettre en place.`,
          timestamp: new Date().toLocaleTimeString()
        };
        setMessages([initialMsg]);
        localStorage.setItem(storageKey, JSON.stringify([initialMsg]));
      }
    }
  }, [agent, prospectName, storageKey]);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem(storageKey, JSON.stringify(messages));
    }
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, storageKey]);

  const selectModel = (messageCount: number, text: string): string => {
    const complexKeywords = ['closing', 'tarif', 'infrastructure', 'architecture', 'integration'];
    const isComplex = complexKeywords.some(k => text.toLowerCase().includes(k));

    if (messageCount > 6 || isComplex) return 'gemini-3-pro-preview';
    return 'gemini-3-flash-preview';
  };

  const handleSendMagicLink = async () => {
    const identity = visitorMemory.getIdentity();
    if (!identity) return;

    setIsSendingLink(true);
    const link = visitorMemory.generateMagicLink(identity);

    // Simulation d'envoi d'email
    setTimeout(() => {
      const action: FollowUpRecord = {
        id: `ML-${Date.now()}`,
        targetId: '1',
        targetName: identity.firstName,
        channel: 'email',
        scenario: 'MAGIC_LINK_CONTINUITY',
        tone: 'strategique',
        message: FIKO_EMAIL_TEMPLATES.MAGIC_LINK.body.replace('{{Prénom}}', identity.firstName).replace('{{Link}}', link),
        sentAt: new Date().toISOString(),
        status: 'sent',
        type: 'auto'
      };

      const logs = JSON.parse(localStorage.getItem('krypton_fiko_actions_log') || '[]');
      localStorage.setItem('krypton_fiko_actions_log', JSON.stringify([...logs, action]));

      setIsSendingLink(false);
      setMagicLinkSent(true);

      // Ajouter une réponse de FIKO confirmant l'envoi
      setMessages(prev => [...prev, {
        role: 'model',
        text: `C'est fait. Je viens de vous envoyer un Magic Link sécurisé par email. Vous pourrez reprendre cette conversation exactement là où nous en sommes, sur votre mobile ou n'importe quel autre appareil, en un clic.`,
        timestamp: new Date().toLocaleTimeString()
      }]);
    }, 1500);
  };

  const simulateMultichannelAction = () => {
    const actions = JSON.parse(localStorage.getItem('krypton_fiko_actions_log') || '[]');
    const hasAlreadySentConfirmation = actions.some((a: any) => a.scenario === 'CONFIRMATION');

    if (!hasAlreadySentConfirmation) {
      const identity = visitorMemory.getIdentity();
      const confirmationAction: FollowUpRecord = {
        id: `A-${Date.now()}`,
        targetId: '1',
        targetName: prospectName || 'Visiteur',
        channel: 'email',
        scenario: 'CONFIRMATION',
        tone: 'strategique',
        message: FIKO_EMAIL_TEMPLATES.CONFIRMATION.body.replace('{{Prénom}}', prospectName || 'Visiteur').replace('{{Objectif}}', 'votre projet IA'),
        sentAt: new Date().toISOString(),
        status: 'sent',
        type: 'auto'
      };

      localStorage.setItem('krypton_fiko_actions_log', JSON.stringify([...actions, confirmationAction]));
      console.log("[FIKO MULTICHANNEL] Email de confirmation planifié.");
    }
  };

  const handleSend = async () => {
    if (!input.trim() || !agent) return;

    const startTime = Date.now();
    const userMsgText = input;
    const userMsg: Message = { role: 'user', text: userMsgText, timestamp: new Date().toLocaleTimeString() };

    setInput('');
    setMessages(prev => [...prev, userMsg]);
    setIsTyping(true);

    try {
      const selectedModel = selectModel(messages.length, userMsgText);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const historyForAI = messages.concat(userMsg).map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const response = await ai.models.generateContent({
        model: selectedModel,
        contents: historyForAI,
        config: {
          systemInstruction: FIKO_MASTER_CLOSER_PROMPT + `\n\nCONTEXTE PROSPECT : Prénom: ${prospectName || 'Inconnu'}. 
DIRECTIVE DE MÉMOIRE : Maintenez la continuité.
TON : Humain, fluide, non robotique.
MULTICHANNEL : Vous êtes autorisé à proposer un MAGIC LINK pour la continuité sur mobile si le prospect semble vouloir quitter ou continuer ailleurs.`,
          thinkingConfig: selectedModel.includes('pro') ? { thinkingBudget: 25000 } : undefined,
          temperature: 0.7,
        }
      });

      const latency = Date.now() - startTime;
      const aiText = response.text || "Analyse en cours. Précisez votre pensée.";
      const modelMsg: Message = { 
        role: 'model', 
        text: aiText, 
        timestamp: new Date().toLocaleTimeString(),
        latency,
        modelUsed: selectedModel
      };
      setMessages(prev => [...prev, modelMsg]);

      if (messages.length === 1) {
        simulateMultichannelAction();
      }
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Liaison sécurisée maintenue. Veuillez reformuler.", timestamp: new Date().toLocaleTimeString() }]);
    } finally {
      setIsTyping(false);
    }
  };

  const clearHistory = () => {
    if (window.confirm("Réinitialiser la liaison avec FIKO™ ?")) {
      localStorage.removeItem(storageKey);
      setMessages([{ 
        role: 'model', 
        text: `Bonjour ${prospectName || ''}, je suis FIKO. Reprenons notre échange stratégique.`,
        timestamp: new Date().toLocaleTimeString()
      }]);
    }
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[160] bg-black/95 backdrop-blur-3xl flex items-center justify-center p-0 md:p-10 animate-in fade-in duration-500">
      <div className="bg-[#0B0B0F] border border-white/10 w-full max-w-5xl h-full md:h-[90vh] flex flex-col rounded-sm shadow-[0_0_150px_rgba(225,6,0,0.2)] overflow-hidden relative">
        <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>

        <button onClick={onClose} className="absolute top-6 right-6 z-[70] size-14 flex items-center justify-center text-slate-500 hover:text-white transition-all hover:bg-white/5 rounded-full group shadow-lg">
          <LucideX size={32} className="group-hover:rotate-90 transition-transform" />
        </button>

        <div className="bg-[#1A1A1F] p-8 border-b border-white/10 flex items-center justify-between relative z-10">
          <div className="flex items-center gap-6">
            <div className="relative">
              <div className="size-16 bg-[#E10600]/10 border border-[#E10600]/30 flex items-center justify-center rounded-sm">
                <LucideBot className="text-[#E10600]" size={32} />
              </div>
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full border-4 border-[#1A1A1F] animate-pulse"></div>
            </div>
            <div>
              <div className="flex items-center gap-3">
                <h3 className="font-black uppercase tracking-[0.2em] text-lg">Liaison FIKO™ v1.3</h3>
                <span className="bg-emerald-500/10 text-emerald-500 text-[8px] font-black px-2 py-0.5 uppercase tracking-widest rounded-sm border border-emerald-500/20">MULTICHANNEL_LINK ACTIVE</span>
              </div>
              <p className="text-[10px] text-slate-500 uppercase tracking-[0.3em] font-bold mt-1 flex items-center gap-2">
                <LucideShieldCheck size={12} className="text-emerald-500" /> PROSPECT : {prospectName?.toUpperCase() || 'IDENTIFIÉ'}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-6 mr-20">
            <button 
                onClick={handleSendMagicLink}
                disabled={magicLinkSent || isSendingLink}
                className={`flex items-center gap-3 px-6 py-3 border text-[9px] font-black uppercase tracking-widest transition-all ${magicLinkSent ? 'border-emerald-500/30 text-emerald-500 bg-emerald-500/5' : 'border-white/10 text-slate-500 hover:text-white hover:bg-white/5'}`}
                title="Continuer sur mobile via Magic Link"
            >
                {isSendingLink ? <LucideLoader2 size={14} className="animate-spin" /> : magicLinkSent ? <LucideCheck size={14} /> : <LucideSmartphone size={14} />}
                {magicLinkSent ? 'Lien Envoyé' : 'Continuer sur Mobile'}
            </button>
            <button onClick={clearHistory} className="text-[9px] font-black uppercase tracking-widest text-slate-600 hover:text-[#E10600] transition-colors flex items-center gap-2 group">
                <LucideClock size={14} className="group-hover:rotate-12 transition-transform" /> RESET SESSION
            </button>
          </div>
        </div>

        <div ref={scrollRef} className="flex-grow overflow-y-auto p-10 space-y-12 scroll-smooth relative z-10 custom-scrollbar">
          {messages.map((m, i) => (
            <div key={i} className={`flex gap-8 ${m.role === 'model' ? 'flex-row' : 'flex-row-reverse animate-in slide-in-from-right-4 duration-300'}`}>
              <div className={`size-12 flex-shrink-0 flex items-center justify-center rounded-sm transition-all shadow-xl ${m.role === 'model' ? 'bg-[#E10600] text-white' : 'bg-white text-black'}`}>
                {m.role === 'model' ? <LucideBot size={24} /> : <LucideUser size={24} />}
              </div>
              <div className={`max-w-[85%] p-10 rounded-sm text-lg lg:text-xl leading-relaxed relative ${m.role === 'model' ? 'bg-black border border-[#E10600]/20 text-white font-medium fiko-message' : 'bg-white/5 border border-white/10 text-white italic font-medium backdrop-blur-md'}`}>
                {m.role === 'model' && i > 0 && <div className="absolute -top-4 left-4 px-3 py-1 bg-[#E10600] text-white text-[8px] font-black uppercase tracking-[0.3em] rounded-sm flex items-center gap-2"><LucideSparkles size={10} /> NEURAL_INSIGHT</div>}
                {m.text.split('\n').map((line, idx) => <p key={idx} className={idx > 0 ? 'mt-4' : ''}>{line}</p>)}
                {m.role === 'model' && m.latency && (
                    <div className="mt-4 pt-4 border-t border-white/5 flex items-center justify-between text-[8px] font-black uppercase tracking-widest text-slate-700">
                        <span className="flex items-center gap-2"><LucideNetwork size={10} /> Model: {m.modelUsed?.split('-')[2]}</span>
                        <span className="flex items-center gap-2"><LucideActivity size={10} /> Latency: {m.latency}ms</span>
                    </div>
                )}
                {m.role === 'model' && <div className="absolute top-0 left-0 w-1.5 h-full bg-[#E10600]"></div>}
                <span className={`absolute -bottom-6 ${m.role === 'model' ? 'left-0' : 'right-0'} text-[8px] font-black text-slate-700 uppercase tracking-widest`}>
                  {m.timestamp}
                </span>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex gap-8">
              <div className="size-12 bg-[#E10600] text-white flex items-center justify-center rounded-sm shadow-[0_0_20px_#E10600] animate-pulse">
                <LucideSparkles size={24} className="animate-spin duration-[3s]" />
              </div>
              <div className="bg-black border border-[#E10600]/10 p-10 rounded-sm flex flex-col gap-4 max-w-[80%] shadow-inner relative overflow-hidden">
                <div className="absolute inset-0 bg-red-600/5 animate-pulse"></div>
                <div className="relative z-10">
                   <p className="text-[10px] font-black uppercase tracking-[0.4em] text-[#E10600] mb-3 flex items-center gap-2">
                     <LucideShieldAlert size={14} className="animate-bounce" /> FIKO™ SHADOW MODE AUDIT V1.3...
                   </p>
                   <div className="space-y-2">
                     <div className="h-1 bg-white/5 w-full rounded-full overflow-hidden">
                        <div className="h-full bg-[#E10600] animate-[shimmer_2s_infinite] w-[60%]"></div>
                     </div>
                     <p className="text-[8px] font-bold text-slate-700 uppercase tracking-widest italic">Analyse des signaux multicanaux...</p>
                   </div>
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="p-10 border-t border-white/10 bg-[#0B0B0F]/90 backdrop-blur-3xl relative z-10">
          <div className="max-w-4xl mx-auto relative group">
            <input 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyDown={(e) => e.key === 'Enter' && handleSend()} 
              placeholder="DIRECTIVE STRATÉGIQUE POUR FIKO™..." 
              className="w-full bg-black border border-white/10 p-8 pr-28 text-sm font-black uppercase tracking-[0.4em] text-white outline-none focus:border-[#E10600] transition-all placeholder:text-slate-900 shadow-2xl" 
              autoFocus 
            />
            <button 
              onClick={handleSend} 
              disabled={isTyping || !input.trim()} 
              className="absolute right-6 top-1/2 -translate-y-1/2 bg-[#E10600] p-5 text-white hover:bg-red-700 transition-all rounded-sm shadow-xl disabled:opacity-50"
            >
              <LucideSend size={24} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AIChatOverlay;

export enum Page {
  HOME = 'home',
  AGENTS = 'agents',
  VOICE = 'voice',
  CRM = 'crm',
  SCRAPER = 'scraper',
  TRUST = 'trust',
  PRICING = 'pricing',
  CLIENT_DASHBOARD = 'client_dashboard',
  ADMIN_DASHBOARD = 'admin_dashboard',
  AUTH = 'auth',
  WHITEPAPER = 'whitepaper',
  FIKO = 'fiko'
}

export enum UserRole {
  CLIENT = 'client',
  ADMIN = 'admin',
  SUPER_ADMIN = 'super_admin'
}

export interface UserProfile {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  role: UserRole;
  avatar?: string;
  company?: string;
}

export interface ProspectInfo {
  firstName: string;
  phone: string;
  email: string;
  visitorId?: string;
  lastSeen?: string;
  isNewDevice?: boolean;
}

export interface TrustedDevice {
  email: string;
  visitorId: string;
  firstSeen: string;
  lastSeen: string;
  userAgent: string;
}

export interface MagicLinkContext {
  prospect: ProspectInfo;
  gate?: string;
  step?: string;
  timestamp: string;
}

export type FikoAutopilotStatus = 'OBSERVATION' | 'INTERVENTION' | 'SILENCE_STRATÉGIQUE' | 'COOLDOWN';
export type SystemStatus = 'ONLINE' | 'DEGRADED' | 'OFFLINE';
export type OptimizationMode = 'ECO' | 'STANDARD' | 'PREMIUM' | 'AUTO';

export interface AutopilotDecision {
  id: string;
  timestamp: string;
  signal: string;
  action: 'EMAIL' | 'CHAT' | 'VOICE' | 'SILENCE';
