import { MASTER_AGENTS, UNIVERSAL_DISCOVERY_PROMPT } from '../constants';
import { 
  Search, Hexagon, Mic, Bolt, BrainCircuit, Activity, Loader2, ArrowRight, 
  Target, MessageSquare, Sparkles, Cpu, ShieldCheck, Database, LayoutGrid, 
  Zap, ChevronRight, Fingerprint, Network, Globe
} from 'lucide-react';
