function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  prospectName?: string;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, prospectName, onClose, onOpenCheckout, initialPorte }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));

  // MODULE 4 ML ENGINE STATE
  const [priorityScore, setPriorityScore] = useState(0);
  const [decisionScore, setDecisionScore] = useState(0);
  const [fakeDecisionScore, setFakeDecisionScore] = useState(0);
  const [buyingMoment, setBuyingMoment] = useState<BuyingWindow>(BuyingWindow.LATER);
  const [ltvClass, setLtvClass] = useState<LTVClass>(LTVClass.BRONZE);
  const [transcription, setTranscription] = useState("");
  const [sessionHistory, setSessionHistory] = useState<string[]>([]);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const storageKey = `krypton_fiko_vocal_history`;

  // Chargement historique transcriptions
  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) setSessionHistory(JSON.parse(saved));
  }, []);

  useEffect(() => {
    if (!transcription) return;
    const text = transcription.toLowerCase();

    // Mise à jour de l'historique
    setSessionHistory(prev => {
        const newHistory = [...prev, transcription].slice(-10); // Garder les 10 derniers échanges
        localStorage.setItem(storageKey, JSON.stringify(newHistory));
        return newHistory;
    });

    // ANALYSE LINGUISTIQUE TEMPS RÉEL (Signaux du Module 4)
    const hasI = (text.match(/\b(je|moi|mon|ma|mes)\b/g) || []).length;
    const hasWe = (text.match(/\b(nous|on|équipe|direction|comité)\b/g) || []).length;
    const hasNow = text.includes("maintenant") || text.includes("urgent") || text.includes("prix") || text.includes("virement");
    const hasComplexity = text.includes("automatisation") || text.includes("architecture") || text.includes("infrastructure");

    setDecisionScore(prev => Math.min(100, Math.max(0, prev + (hasI * 12) - (hasWe * 5))));

    if (text.includes("en parler à") || text.includes("réfléchir") || text.includes("plus tard")) {
      setFakeDecisionScore(prev => Math.min(100, prev + 20));
    }

    if (hasNow) setBuyingMoment(BuyingWindow.NOW);
    if (hasComplexity) setLtvClass(LTVClass.GOLD);
    if (hasComplexity && (text.includes("groupe") || text.includes("international"))) setLtvClass(LTVClass.PLATINUM);

    // CALCUL DU SCORE PRIORITÉ COMBINÉ (Cerveau du Module 3)
    const calcPriority = () => {
      const dWeight = decisionScore * 0.35;
      const bWeight = (buyingMoment === BuyingWindow.NOW ? 100 : 30) * 0.35;
      const lWeight = (ltvClass === LTVClass.PLATINUM ? 100 : ltvClass === LTVClass.GOLD ? 70 : 40) * 0.3;
      const fPenalty = fakeDecisionScore * 0.25;
      return Math.max(0, Math.min(100, Math.round(dWeight + bWeight + lWeight - fPenalty)));
    };

    setPriorityScore(calcPriority());
  }, [transcription]);

  const stopSession = useCallback(() => {
    setStep('pre_start');
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current) inputAudioContextRef.current.close();
    if (outputAudioContextRef.current) outputAudioContextRef.current.close();
    if (sessionRef.current) sessionRef.current.close();
    sessionRef.current = null;
    inputAudioContextRef.current = null;
    outputAudioContextRef.current = null;
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    try {
      const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
      const inputCtx = new AudioContextClass({ sampleRate: 16000 });
      const outputCtx = new AudioContextClass({ sampleRate: 24000 });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active');
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 1000 + 5)) + 5));

              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;

              sessionPromise.then(s => s.sendRealtimeInput({ 
                media: { 
                  data: encode(new Uint8Array(int16.buffer)), 
                  mimeType: 'audio/pcm;rate=16000' 
                } 
              }));
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (m: LiveServerMessage) => {
            if (m.serverContent?.inputTranscription) {
              setTranscription(m.serverContent.inputTranscription.text);
            }

            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error('Vertex Link Error:', e);
            stopSession();
          },
          onclose: () => stopSession()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: `${FIKO_MASTER_CLOSER_PROMPT}

DIRECTIVE CRITIQUE : Active le SHADOW MODE en temps réel. Analyse chaque signal, matche avec le wiki et vérifie la cohérence avant de générer l'audio.
CONTINUITÉ STRATÉGIQUE : Voici les derniers points abordés avec le prospect : ${sessionHistory.join(' | ')}. Utilisez cette mémoire pour un closing cohérent.
RECONNAISSANCE PROSPECT : Le prospect s'appelle ${prospectName || 'un visiteur'}. 
RÈGLE D'INTRODUCTION : Saluez le par son prénom systématiquement. Dites : "Bonjour ${prospectName || 'à vous'}, je suis FIKO. Merci d’avoir pris le temps. Parlons de ce que vous cherchez à mettre en place."`
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) {
      console.error('Activation Error:', e);
      setStep('pre_start');
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[170] bg-black flex flex-col items-center justify-center p-6 overflow-hidden"
    >
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>

