            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em] mt-1">Partner Dash v1.3</p>
          </div>
        </div>
        <nav className="flex-grow py-8 px-6 space-y-2 overflow-y-auto custom-scrollbar">
          {[
