  const [leads, setLeads] = useState<Lead[]>([]);
  const [followUps, setFollowUps] = useState<FollowUpRecord[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [autopilotEnabled, setAutopilotEnabled] = useState(true);
  const [isInferenceLoading, setIsInferenceLoading] = useState<string | null>(null);

  // VIVALEADS STATE
  const [activeVivaTab, setActiveVivaTab] = useState<'dashboard' | 'wizard' | 'vault' | 'mailing'>('dashboard');
  const [vivaCampaigns] = useState<VivaCampaign[]>(MOCK_VIVA_CAMPAIGNS);
  const [vivaLeads] = useState<VivaLead[]>(MOCK_VIVA_LEADS);
  const [isScraping, setIsScraping] = useState(false);

  // MONITORING STATE
  const [metrics, setMetrics] = useState<MonitoringMetrics>({
    status: 'ONLINE',
    activeSessions: 42,
    avgLatencyText: 840,
    avgLatencyVoice: 1250,
    p95Latency: 1800,
    errorRate: 0.2,
    costMTD: 1420.50,
    optimizationMode: 'AUTO'
  });

  const costBreakdown: CostBreakdown = {
    nlp: 850.30,
    tts: 420.20,
    embeddings: 120.00,
    other: 30.00
  };

  const pieData = [
    { name: 'NLP', value: costBreakdown.nlp, fill: '#E10600' },
    { name: 'TTS', value: costBreakdown.tts, fill: '#E10600BB' },
    { name: 'Embeddings', value: costBreakdown.embeddings, fill: '#E1060088' },
    { name: 'Infrastructure', value: costBreakdown.other, fill: '#333' },
  ];

  useEffect(() => {
    const savedLeads = JSON.parse(localStorage.getItem('krypton_crm_leads') || '[]');
    setLeads([...LEADS, ...savedLeads]);

    const mockFollowUps: FollowUpRecord[] = [
      { id: 'F-1', targetId: 'L-001', targetName: 'Koffmann Invest', channel: 'email', scenario: 'CONFIRMATION', tone: 'strategique', message: FIKO_EMAIL_TEMPLATES.CONFIRMATION.body.replace('{{Prénom}}', 'Koffmann'), sentAt: new Date(Date.now() - 3600000).toISOString(), status: 'opened', type: 'auto' },
      { id: 'F-2', targetId: 'L-002', targetName: 'Sahel Logistique', channel: 'chat', scenario: 'RELANCE_DOUCE', tone: 'soft', message: FIKO_EMAIL_TEMPLATES.FOLLOW_UP_SOFT.body.replace('{{Prénom}}', 'Arouna'), sentAt: new Date(Date.now() - 7200000).toISOString(), status: 'sent', type: 'auto' }
    ];
    setFollowUps(mockFollowUps);

    if (user?.role !== UserRole.SUPER_ADMIN && user?.role !== UserRole.ADMIN) {
      onNavigate(Page.HOME);
    }
    const timer = setTimeout(() => setLoading(false), 1500);

    const metricsInterval = setInterval(() => {
        setMetrics(prev => ({
            ...prev,
            activeSessions: Math.floor(prev.activeSessions + (Math.random() * 5 - 2)),
            avgLatencyText: Math.floor(800 + Math.random() * 100),
            errorRate: Math.random() * 0.5
        }));
    }, 5000);

    return () => {
        clearTimeout(timer);
        clearInterval(metricsInterval);
    };
  }, [user, onNavigate]);

  const fikoPerformance = useMemo(() => ({
    responseRate: 74.2,
    activationRate: 38.5,
    closingRate: 22.8,
    recoveredRevenue: "1.42B FCFA"
  }), []);

  const filteredLeads = useMemo(() => {
    return leads.filter(l => 
      l.entity.toLowerCase().includes(searchQuery.toLowerCase()) || 
      l.email.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [leads, searchQuery]);

  const setOptiMode = (mode: OptimizationMode) => {
    setMetrics(prev => ({ ...prev, optimizationMode: mode }));
  };

  const runAutopilotInference = async (lead: Lead) => {
    setIsInferenceLoading(lead.id);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyse le lead suivant et propose une action de closing immédiate : ${JSON.stringify(lead)}`,
        config: { systemInstruction: FIKO_AUTOPILOT_MASTER_PROMPT }
      });

      const newAction: FollowUpRecord = {
        id: `F-AUTO-${Date.now()}`,
        targetId: lead.id,
        targetName: lead.entity,
        channel: 'email',
        scenario: 'AUTOPILOT_CLOSING_SYNC',
        tone: 'strategique',
        message: response.text || "Analyse autopilot complétée.",
        sentAt: new Date().toISOString(),
        status: 'sent',
        type: 'auto'
      };
      setFollowUps(prev => [newAction, ...prev]);
    } catch (error) {
      console.error("[AUTOPILOT ERROR]", error);
    } finally {
      setIsInferenceLoading(null);
    }
  };

  const sendManualFollowUp = async (lead: Lead) => {
    setIsInferenceLoading(`manual-${lead.id}`);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un email de relance doux et professionnel pour le prospect ${lead.entity}.`,
        config: { systemInstruction: "Tu es FIKO, un expert en closing commercial." }
      });

      const newAction: FollowUpRecord = {
        id: `F-MANUAL-${Date.now()}`,
        targetId: lead.id,
        targetName: lead.entity,
        channel: 'email',
        scenario: 'RELANCE_MANUELLE_DASHBOARD',
        tone: 'soft',
        message: response.text || "Relance manuelle générée et envoyée.",
        sentAt: new Date().toISOString(),
        status: 'sent',
        type: 'manual'
      };
      setFollowUps(prev => [newAction, ...prev]);
    } catch (error) {
      console.error("[MANUAL FOLLOWUP ERROR]", error);
    } finally {
      setIsInferenceLoading(null);
    }
  };

  const getStatusColor = (status: SystemStatus | string) => {
    switch(status) {
      case 'ONLINE': return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/30 shadow-[0_0_15px_#10b98122]';
      case 'DEGRADED': return 'text-orange-500 bg-orange-500/10 border-orange-500/30';
      case 'OFFLINE': return 'text-red-500 bg-red-500/10 border-red-500/30 shadow-[0_0_15px_#E1060022]';
      case 'hot': return 'text-[#E10600] bg-[#E10600]/10 border-[#E10600]/30';
      default: return 'text-slate-500 bg-white/10 border-white/10';
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-10">
      <Hexagon size={100} className="text-[#E10600] animate-[spin_10s_linear_infinite]" strokeWidth={1} />
      <p className="text-[10px] font-black uppercase tracking-[0.8em] text-[#E10600]">KRYPTON HQ SYNC...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex overflow-hidden font-sans selection:bg-[#E10600]">

      <aside className="w-80 bg-[#0A0A0E] border-r border-white/5 flex flex-col z-50">
        <div className="p-10 border-b border-white/5 flex items-center gap-5">
          <div className="size-12 bg-white text-black rounded-sm flex items-center justify-center shadow-[0_0_30px_rgba(255,255,255,0.1)]"><Crown size={24} /></div>
          <div>
            <p className="font-black uppercase tracking-tighter text-2xl leading-none">KRYPTON <span className="text-[#E10600]">HQ</span></p>
            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.4em] mt-1">Master Controller v10.1</p>
