interface AuthPageProps {
  onLoginSuccess: (user: UserProfile) => void;
  onNavigate: (p: Page) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess, onNavigate }) => {
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [role, setRole] = useState<UserRole>(UserRole.CLIENT);
  const [isLoading, setIsLoading] = useState(false);
  const [focusedField, setFocusedField] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    company: ''
  });

  const handlePasswordChange = (val: string) => {
    const numericValue = val.replace(/[^0-9]/g, '');
    setFormData({ ...formData, password: numericValue });
  };

  const handleQuickLogin = (targetRole: UserRole) => {
    setIsLoading(true);
    setTimeout(() => {
      const mockUser: UserProfile = {
        id: 'DEMO-' + Math.random().toString(36).substr(2, 4).toUpperCase(),
        firstName: targetRole === UserRole.SUPER_ADMIN ? 'Super' : targetRole === UserRole.ADMIN ? 'Admin' : 'Client',
        lastName: 'Demo',
        email: `${targetRole.toLowerCase()}@krypton.ai`,
        role: targetRole,
        company: 'Krypton AI Systems',
        subscription: targetRole === UserRole.CLIENT ? {
          plan: 'pro',
          leadsUsed: 420,
          leadsLimit: 5000,
          campaignsCount: 8,
          emailCredits: 350
        } : undefined
      };
      setIsLoading(false);
      onLoginSuccess(mockUser);
    }, 1000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.password.length < 4) return;
    setIsLoading(true);

    setTimeout(() => {
      const mockUser: UserProfile = {
        id: Math.random().toString(36).substr(2, 9),
        firstName: formData.firstName || (role === UserRole.SUPER_ADMIN ? 'SuperAdmin' : role === UserRole.ADMIN ? 'Admin' : 'Client'),
        lastName: formData.lastName || 'Krypton',
        email: formData.email,
        role: role,
        company: formData.company,
        subscription: role === UserRole.CLIENT ? {
          plan: 'free',
          leadsUsed: 0,
          leadsLimit: 500,
          campaignsCount: 0,
          emailCredits: 50
        } : undefined
      };
      setIsLoading(false);
      onLoginSuccess(mockUser);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-[#0B0B0F] flex items-center justify-center p-4 md:p-10 relative overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>

      <button 
        onClick={() => onNavigate(Page.HOME)}
        className="absolute top-8 left-8 z-50 flex items-center gap-3 text-slate-500 hover:text-white transition-all group px-4 py-2 bg-white/5 border border-white/5 rounded-full backdrop-blur-md"
      >
        <ChevronLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
        <span className="text-[10px] font-black uppercase tracking-[0.3em]">Retour</span>
      </button>

      <motion.div initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} className="w-full max-w-[1100px] flex flex-col lg:flex-row bg-[#0D0D12]/80 border border-white/10 rounded-sm shadow-2xl overflow-hidden backdrop-blur-3xl z-10">
        <div className="hidden lg:flex lg:w-[45%] bg-black relative flex-col items-center justify-center p-20 border-r border-white/5">
           <div className="relative z-10 flex flex-col items-center text-center space-y-10">
              <Hexagon size={180} className="text-[#E10600]/20 animate-spin" strokeWidth={0.5} />
              <div className="space-y-4">
                <h2 className="text-3xl font-black uppercase tracking-tighter leading-none italic">AUTH <span className="text-[#E10600]">KRYPTON.</span></h2>
                <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.5em]">SYSTÈME DE SÉCURITÉ NEURALE ACTIVE.</p>
              </div>
           </div>
        </div>

        <div className="flex-grow p-10 md:p-20 overflow-y-auto max-h-[90vh]">
           <div className="mb-12">
              <div className="flex bg-white/5 border border-white/10 p-1 rounded-sm mb-10 w-fit">
                 <button onClick={() => setMode('login')} className={`px-6 py-2 text-[8px] font-black uppercase tracking-widest transition-all ${mode === 'login' ? 'bg-[#E10600] text-white shadow-lg' : 'text-slate-500'}`}>Connexion</button>
                 <button onClick={() => setMode('signup')} className={`px-6 py-2 text-[8px] font-black uppercase tracking-widest transition-all ${mode === 'signup' ? 'bg-[#E10600] text-white shadow-lg' : 'text-slate-500'}`}>Rejoindre</button>
              </div>
              <h1 className="text-4xl font-black uppercase tracking-tighter">{mode === 'login' ? 'Content de vous revoir.' : 'Bienvenue chez les Leaders.'}</h1>
           </div>

           <form onSubmit={handleSubmit} className="space-y-6">
             {mode === 'signup' && (
               <div className="grid grid-cols-2 gap-4">
                 <input required placeholder="PRÉNOM" className="w-full bg-white/5 border-b border-white/10 p-4 text-[10px] font-black text-white outline-none" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
                 <input required placeholder="NOM" className="w-full bg-white/5 border-b border-white/10 p-4 text-[10px] font-black text-white outline-none" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
