             <input required type="password" placeholder="CODE D'ACCÈS" className="w-full bg-white/5 border-b border-white/10 p-4 text-[10px] font-black text-white outline-none" value={formData.password} onChange={e => handlePasswordChange(e.target.value)} />

             <button type="submit" disabled={isLoading} className="w-full bg-[#E10600] py-6 font-black text-[10px] uppercase tracking-[0.4em] flex items-center justify-center gap-4 shadow-2xl active:scale-95 disabled:opacity-50">
               {isLoading ? <Loader2 className="animate-spin" size={16} /> : mode === 'login' ? 'DÉVERROUILLER ACCÈS' : 'ACTIVER MON COMPTE'} <ArrowRight size={18} />
             </button>
           </form>

           {mode === 'login' && (
             <div className="mt-12 pt-10 border-t border-white/5">
                <p className="text-center text-[8px] font-black text-slate-700 uppercase tracking-[0.4em] mb-6">Simulation Accès Direct</p>
                <div className="grid grid-cols-3 gap-4">
                   <button onClick={() => handleQuickLogin(UserRole.CLIENT)} className="flex flex-col items-center gap-2 p-3 bg-white/5 hover:bg-[#E10600]/10 transition-all border border-white/5 group">
                      <User size={14} className="text-slate-600 group-hover:text-white" />
                      <span className="text-[7px] font-black uppercase text-slate-600 group-hover:text-white">Client</span>
                   </button>
                   <button onClick={() => handleQuickLogin(UserRole.SUPER_ADMIN)} className="flex flex-col items-center gap-2 p-3 bg-white/5 hover:bg-[#E10600]/10 transition-all border border-white/5 group">
                      <Crown size={14} className="text-slate-600 group-hover:text-white" />
                      <span className="text-[7px] font-black uppercase text-slate-600 group-hover:text-white">CEO Admin</span>
                   </button>
                </div>
             </div>
           )}
        </div>
      </motion.div>
