    const { color, bg, label } = config[status] || config.standby;
    return (
      <div className={`px-3 py-1 ${bg} border border-white/5 rounded-full flex items-center gap-2`}>
        <span className={`size-1 rounded-full ${color.replace('text-', 'bg-')} animate-pulse shadow-[0_0_8px_currentColor]`}></span>
        <span className={`text-[7px] font-black tracking-[0.2em] ${color} uppercase`}>{label}</span>
      </div>
    );
