      <div className="fixed inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>
      <div className="fixed top-0 left-1/2 -translate-x-1/2 w-full h-full bg-gradient-to-b from-[#E10600]/5 via-transparent to-transparent pointer-events-none"></div>

      {/* Floating Elements pour l'immersion */}
      <div className="absolute top-[20%] left-[-10%] size-[800px] bg-[#E10600]/5 blur-[150px] rounded-full animate-pulse pointer-events-none"></div>
      <div className="absolute bottom-[10%] right-[-10%] size-[800px] bg-blue-600/5 blur-[150px] rounded-full animate-pulse pointer-events-none" style={{ animationDelay: '3s' }}></div>

      <div className="max-w-[1600px] mx-auto px-6 lg:px-20 pt-40 pb-60 relative z-10">

        {/* TITRE MONUMENTAL */}
        <div className="relative mb-32">
