                 <button onClick={() => setMode('signup')} className={`px-6 py-2 text-[8px] font-black uppercase tracking-widest transition-all ${mode === 'signup' ? 'bg-[#E10600] text-white shadow-lg' : 'text-slate-500'}`}>Rejoindre</button>
