                      <span className="text-[10px] text-slate-700 font-bold mb-1.5">%</span>
                   </div>
                </div>
                <div>
                   <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mb-1">PORTE ESTIMÉE</p>
                   <span className="text-xl font-black uppercase tracking-tighter" style={{ color: activeColor }}>
                      {recommendedGate}
                   </span>
                </div>
             </div>
          </div>

        </div>
      </main>

      <footer className="absolute bottom-0 w-full h-16 px-10 flex items-center justify-center border-t border-white/5 bg-black/40 backdrop-blur-xl z-20">
        <p className="text-[10px] text-slate-600 font-bold uppercase tracking-widest">
