}
          `}</CodeBlock>
        </Section>

        <Section title="3. Structure Officielle des Produits" icon={<DollarSign />}>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {products.map(p => (
              <div key={p.name} className="bg-black/40 p-6 border border-white/10 rounded-sm space-y-3">
                <h3 className="font-black text-white uppercase">{p.name}</h3>
                <p className="text-lg font-mono text-[#E10600]">{p.price}</p>
                <p className="text-xs text-slate-400">Maintenance: <span className="font-bold">{p.maintenance}</span> (post-6 mois)</p>
                {p.minutes && <p className="text-xs text-slate-400">Quota Voix: <span className="font-bold">{p.minutes}</span></p>}
              </div>
            ))}
          </div>
        </Section>

        <Section title="4. Logique de Facturation Automatique" icon={<Clock />}>
          <div className="grid md:grid-cols-2 gap-8">
            <div>
              <h4 className="font-bold text-white uppercase tracking-widest mb-4">A. Activation</h4>
              <CodeBlock>{`
if (payment_success) {
  activate_plan();
  set_activation_date();
  set_maintenance_start_date(activation_date + 6 months);
  set_voice_limit(); // if applicable
}
              `}</CodeBlock>
            </div>
            <div>
              <h4 className="font-bold text-white uppercase tracking-widest mb-4">B. Déclenchement Maintenance</h4>
               <CodeBlock>{`
// Daily Cloud Scheduler Job
if (today >= maintenance_start_date && !maintenance_active) {
  set_maintenance_active(true);
  create_stripe_subscription();
}
              `}</CodeBlock>
            </div>
          </div>
        </Section>

        <Section title="5. Contrôle des Minutes Vocales (Gemini Live)" icon={<Mic />}>
            <div className="grid md:grid-cols-2 gap-8 items-center">
                <CodeBlock>{`
// On each Gemini Live session end
const session_duration_minutes = get_session_duration();
update_client_minutes(client_id, session_duration_minutes);

// Cloud Function Trigger on client update
if (client.voice_minutes_used >= client.voice_minutes_limit) {
  block_voice_access(client_id);
}
                `}</CodeBlock>
                <div className="bg-red-900/40 border border-red-500/30 p-8 text-center space-y-4">
                    <AlertTriangle className="mx-auto text-red-400" size={32} />
                    <p className="text-sm font-black uppercase text-white">Message Client:</p>
                    <p className="text-slate-300 italic">“Votre quota mensuel est atteint. Achetez un pack minutes pour réactiver le service.”</p>
                </div>
            </div>
        </Section>

        <Section title="7. Protection Marge Gemini" icon={<ShieldAlert />}>
            <div className="grid md:grid-cols-3 gap-6">
                {['Limite max de session (15 min)', 'Timeout automatique inactivité', 'Cache réponses récurrentes', 'Logs consommation API temps réel'].map(rule => (
                    <div key={rule} className="bg-white/5 p-6 border border-white/5 rounded-sm text-center">
                        <p className="text-xs font-black uppercase text-slate-300 tracking-widest">{rule}</p>
                    </div>
                ))}
            </div>
        </Section>

        <Section title="9. Dashboard Admin Krypton" icon={<TrendingUp />}>
            <p className="text-slate-400 italic mb-6">Le CEO Dashboard doit impérativement afficher les métriques suivantes pour un pilotage optimal :</p>
            <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-4">
                {['Total Revenus Mensuels', 'Coût API Gemini Estimé', 'Marge Brute / Client', 'Usage Minutes / Client', 'Clients à Risque (Paiement)'].map(metric => (
                    <div key={metric} className="p-4 bg-black/40 border border-white/10 text-center text-xs font-bold uppercase tracking-wider">{metric}</div>
                ))}
            </div>
        </Section>
      </main>
    </div>
  );
};

